const CONFIG = {
  defaultTheme: 'R61G150B51',
  seasonalTheme: false, // will change the default theme based on the date
  effectsDisabledByDefault: false,
  effectsDisabledByDefaultMobile: true,
  displayEffectsSwitch: true,
  crtEffect: true,
  noiseEffect: true,
  grungeOverlay: true,
  defaultHash: '#about',
  animationOnTabChange: true, // disabled when effects are disabled
  writeAnimationOnTabChange: false, // animationOnTabChange must be true | may cause performance issues
  blogUrl: 'https://data.richardapps.net/blog.xml', // example: '/src/example/blog.xml'
  useExample: false,
  writeAnimationOnPostOpen: true,
  showEstimatedReadTime: true,
};
function copyClipboard(text, element = null, copyIndicator = 'Copied!') {
  navigator.clipboard
    .writeText(text)
    .then(() => {
      if (element) {
        const originalText = element.textContent;
        element.textContent = copyIndicator;
        element.style.pointerEvents = 'none';
        setTimeout(() => {
          element.textContent = originalText;
          element.style.pointerEvents = 'auto';
        }, 1500);
      }
    })
    .catch((error) => console.error(error));
}
function initTooltips() {
  const tooltipElement = document.createElement('div');
  tooltipElement.classList.add('tooltip');
  tooltipElement.style.display = 'none';
  document.body.appendChild(tooltipElement);
  const tooltips = document.querySelectorAll('[data-tooltip]');
  tooltips.forEach((tooltip) => {
    tooltip.addEventListener('mouseenter', () => {
      const tooltipText = tooltip.getAttribute('data-tooltip');
      tooltipElement.textContent = tooltipText;
      tooltipElement.style.display = 'block';
    });
    tooltip.addEventListener('mousemove', (event) => {
      const tooltipElement = document.querySelector('.tooltip');
      tooltipElement.style.top = `${event.clientY + 10}px`;
      tooltipElement.style.left = `${event.clientX + 10}px`;
    });
    tooltip.addEventListener('mouseleave', () => {
      tooltipElement.style.display = 'none';
    });
  });
}
function ImgLazyLoading() {
  document.addEventListener("DOMContentLoaded", function() {
    const images = document.querySelectorAll('img');
    images.forEach(img => {
      img.setAttribute('loading', 'lazy');
    });
  });
}
const THEMES = {
  R61G150B51: {
    bgColor: 'rgb(61, 150, 51)',
    mainColor: '#6dfd60',
    selection: '#3b8b42',
  },
  R192G63B63: {
    bgColor: 'rgb(192, 63, 63)',
    mainColor: '#fd6060',
    selection: '#8b3b3b',
  },
  R179G105B21: {
    bgColor: 'rgb(179, 105, 21)',
    mainColor: '#fda93c',
    selection: '#946612',
  },
  R9G95B92: {
    bgColor: 'rgb(9, 95, 92)',
    mainColor: '#cbe9d1',
    selection: '#56705a',
  },
};
function removeRGB(rgb) {
  return rgb
    .replace(/rgb\(|\)/g, '')
    .split(',')
    .map((n) => parseInt(n));
}
function changeTheme(theme, save = true) {
  const settings = THEMES[theme];
  if (!settings) return;
  const rawBG = removeRGB(settings.bgColor);
  document.documentElement.style.setProperty('--bg-color', rawBG.join(', '));
  document.documentElement.style.setProperty('--selection', settings.selection);
  document.documentElement.style.setProperty('--main-color', settings.mainColor);
  document.documentElement.style.setProperty('--main-color-40', settings.mainColor + '66'); // main-color with 40% opacity (Adding hex alpha AA (66 for 40% in this case) to #RRGGBB)
  if (save) {
    localStorage.setItem('theme', theme);
  }
  const rainVideo = document.getElementById('rain-vid');
  const snowContainer = document.getElementById('snow-container');
  rainVideo.style.display = 'none';
  snowContainer.innerHTML = '';
  switch (theme) {
    case 'rainy':
      rainVideo.style.display = 'block';
      break;
    case 'winter':
      snowAnimation();
      break;
  }
  if (document.getElementById('theme-list')) {
    document.querySelectorAll('#theme-list p a').forEach((link) => {
      link.textContent = link.dataset.theme === theme ? `> ${theme} <` : link.dataset.theme;
    });
  }
}
function addThemeList() {
  const THEME_LIST = document.getElementById('theme-list');
  THEME_LIST.innerHTML = '';
  if (THEME_LIST) {
    Object.keys(THEMES).forEach((theme) => {
      const link = document.createElement('a');
      link.href = '#';
      link.dataset.theme = theme;
      link.textContent = theme;
      link.addEventListener('click', (event) => {
        event.preventDefault();
        changeTheme(theme);
      });
      const wrapper = document.createElement('p');
      wrapper.appendChild(link);
      wrapper.id = theme;
      THEME_LIST.appendChild(wrapper);
    });
  }
  if (document.getElementById('rainy')) {
    const rainy = document.getElementById('rainy');
    rainy.style.marginTop = '1em';
  }
  console.log('Theme list added');
}
function initTheme() {
  if (!Object.keys(THEMES).includes(localStorage.getItem('theme'))) {
    localStorage.removeItem('theme');
  }
  if (!Object.keys(THEMES).includes(CONFIG.defaultTheme)) {
    console.error('Default theme set in /src/js/config.js invalid!');
  }
  let THEME =
    localStorage.getItem('theme') ||
    (Object.keys(THEMES).includes(CONFIG.defaultTheme) ? CONFIG.defaultTheme : Object.keys(THEMES)[0]);
  if (CONFIG.seasonalTheme && !localStorage.getItem('theme')) {
    const date = new Date();
    const month = date.getMonth(); // returns value between 0 and 11
    if (month === 11 || month === 0) {
      THEME = Object.keys(THEMES).includes('winter') ? 'winter' : THEME;
    }
  }
  changeTheme(THEME, false);
}
if (CONFIG.effectsDisabledByDefault && !('effectsDisabled' in localStorage)) {
  localStorage.setItem('effectsDisabled', true);
}
let effectsDisabled = localStorage.getItem('effectsDisabled') === 'true';
function updateEffectsState() {
    const toggleLink = document.getElementById('toggle-effects-link');
    if (toggleLink) {
        toggleLink.textContent = effectsDisabled ? 'on' : 'off';
    }
    if (effectsDisabled) {
        if (CONFIG.crtEffect) {
            document.getElementById('canvas').classList.remove('crt-effect');
        }
        document.getElementById('noise-overlay').style.display = 'none';
        document.getElementById('grunge-overlay').style.display = 'none';
        const rainVid = document.getElementById('rain-vid');
        if (rainVid) {
            rainVid.pause();
            rainVid.style.display = 'none';
        }
        const snowContainer = document.getElementById('snow-container');
        if (snowContainer) {
            snowContainer.innerHTML = '';
        }
    } else {
        if (CONFIG.crtEffect) {
            document.getElementById('canvas').classList.add('crt-effect');
        }
        if (CONFIG.noiseEffect) {
            document.getElementById('noise-overlay').style.display = 'block';
        }
        if (CONFIG.grungeOverlay) {
            document.getElementById('grunge-overlay').style.display = 'block';
        }
        if (typeof initTheme === 'function') {
            initTheme();
        }
    }
}
function toggleEffects() {
  effectsDisabled = !effectsDisabled;
  localStorage.setItem('effectsDisabled', effectsDisabled);
  updateEffectsState();
}
function getEffectsDisabledState() {
  return effectsDisabled;
}
function initEffectsToggle() {
  if (!CONFIG.displayEffectsSwitch) {
    document.getElementById('toggle-effects').style.display = 'none';
  } else {
    const nfbText = document.getElementById('toggle-effects');
        nfbText.innerHTML = 'Click <a id="toggle-effects-link" href="#">HERE</a> to turn effects ' + (effectsDisabled ? 'on' : 'off') + '.';
    document.getElementById('toggle-effects-link').addEventListener('click', (event) => {
      event.preventDefault();
      toggleEffects();
    });
        updateEffectsState();
  }
}
function initEffects() {
  if (
    window.matchMedia('(max-width: 767px)').matches &&
    !('effectsDisabled' in localStorage) &&
    CONFIG.effectsDisabledByDefaultMobile
  ) {
    effectsDisabled = true;
  }
  updateEffectsState();
}
const DEFAULT_HASH = CONFIG.defaultHash;
function routing(hash) {
  const [route, query] = hash.slice(1).split('?');
  const params = new URLSearchParams(query || '');
  if (route === 'blog') {
    if (params.has('id')) {
      openPost(params.get('id'));
      document.getElementById('blog').classList.add('post-open');
    } else {
      initPosts();
    }
  } else {
    document.getElementById('blog').classList.remove('post-open');
  }
  changeTab(route);
}
function defaultHash() {
  location.hash = DEFAULT_HASH;
}
function removeIDFromHash() {
  location.hash = location.hash.split('?')[0];
}
function initRouting() {
  window.addEventListener('hashchange', function () {
    routing(location.hash);
  });
  routing(location.hash || '#' + DEFAULT_HASH);
}
const CANVAS = document.getElementById('canvas');
function changeTab(newTab) {
  if (newTab === 'home') {
    window.scrollTo(0, 0);
  } else {
    document.getElementById('nav-tabs').scrollIntoView({ behavior: 'smooth' });
  }
  document.querySelectorAll('.tab-switcher').forEach((element) => {
    element.classList.remove('tab-active');
  });
  try {
    document.getElementById(newTab + '-tab').classList.add('tab-active');
    if (CONFIG.animationOnTabChange) {
      tabAnimation(newTab);
    }
  } catch (error) {
    defaultHash();
  }
}
function changePictureColl(event, coll) {
  document.querySelectorAll('.pic-coll').forEach((element) => {
    element.style.display = 'none';
  });
  document.getElementById(coll).style.display = 'block';
  document.querySelectorAll('.pic-coll-tabs').forEach((element) => {
    element.classList.remove('tab-active');
  });
  event.target.classList.add('tab-active');
  document.getElementById('nav-tabs').scrollIntoView({ behavior: 'smooth' });
}
function initPictureColl() {
  document.querySelectorAll('.pic-coll-tabs').forEach((element) => {
    element.addEventListener('click', (event) => changePictureColl(event, element.dataset.id));
  });
}
function writeAnimation(element, delay = 5, fadeDuration = 250, blur = false) {
  const content = element.textContent;
  element.textContent = '';
  const wrapper = document.createElement('span');
  wrapper.style.display = 'inline-block';
  element.appendChild(wrapper);
  document.getElementById('canvas').addEventListener('click', () => {
    wrapper.textContent = content;
  });
  for (let i = 0; i < content.length; i++) {
    const letter = document.createElement('span');
    letter.textContent = content[i];
    letter.style.opacity = '0';
    if (blur) {
      letter.style.filter = 'blur(5.5px)';
    }
    letter.style.transition = `opacity ${fadeDuration}ms ease-in-out, filter ${fadeDuration}ms ease-in-out`;
    wrapper.appendChild(letter);
    setTimeout(() => {
      letter.style.opacity = '1';
      if (blur) {
        letter.style.filter = 'blur(0px)';
      }
    }, i * delay);
  }
  setTimeout(() => {
    element.textContent = content;
  }, content.length * delay + fadeDuration);
}
function tabAnimation(tab, fadeInDelay = 16) {
  document.querySelectorAll('.fade-in.visible').forEach((element) => {
    element.classList.remove('visible');
    element.classList.remove('fade-in-anim');
  });
  let elements = document.getElementById(tab).querySelectorAll('*');
  let delay = 0;
  document.getElementById('canvas').addEventListener('click', () => {
    Array.from(elements).forEach((element) => {
      element.classList.add('visible');
      element.classList.add('fade-in-anim');
    });
  });
  Array.from(elements).forEach((element) => {
    element.classList.add('fade-in');
    setTimeout(function () {
      element.classList.add('visible');
      element.classList.add('fade-in-anim');
    }, delay);
    delay += fadeInDelay;
    if (
      CONFIG.writeAnimationOnTabChange &&
      (element.tagName === 'P' ||
        element.tagName === 'A' ||
        element.tagName === 'H1' ||
        element.tagName === 'H2' ||
        element.tagName === 'H3' ||
        element.tagName === 'H4' ||
        element.tagName === 'H5' ||
        element.tagName === 'H6' ||
        element.tagName === 'EM') &&
      !element.innerHTML.includes('<')
    ) {
      writeAnimation(element, 7, 250, true);
    }
  });
}
function snowAnimation() {
  const effectsDisabled = getEffectsDisabledState();
  if (!effectsDisabled) {
    const snowflakeContainer = document.getElementById('snow-container');
    const snowflakeCount = 90;
    const snowflakeSize = 6;
    const snowflakeDuration = 15;
    for (let i = 0; i < snowflakeCount; i++) {
      const snowflake = document.createElement('div');
      snowflake.classList.add('snowflake');
      let size = Math.random() * snowflakeSize + 0.25;
      snowflake.style.width = `${size}px`;
      snowflake.style.height = `${size}px`;
      snowflake.style.left = `${Math.random() * 100}vw`;
      snowflake.style.top = `${Math.random() * -20}vh`;
      snowflake.style.opacity = Math.random() * 0.6 + 0.1;
      snowflake.style.animation = `snowflake-fall ${snowflakeDuration + Math.random() * 10}s linear infinite`;
      if (Math.random() > 0.3) {
        const horizontalAnimation = Math.random() > 0.5 ? 'snowflake-fall-horizontal-1' : 'snowflake-fall-horizontal-2';
        snowflake.style.animation = `${horizontalAnimation} ${snowflakeDuration + Math.random() * 10}s linear infinite`;
      }
      snowflake.style.animationDelay = `-${(snowflakeDuration + Math.random() * 50) / 4}s`; // randomize start
      snowflakeContainer.appendChild(snowflake);
    }
  }
}
const BLOG_URL = CONFIG.useExample ? './src/example/blog.xml' : CONFIG.blogUrl;
const POSTS_CONTAINER = document.getElementById('blog-window');
let cachedPosts = [];
let lastFetched = 0;
let CACHE_DURATION = 300000; // 5 minutes (in ms)
async function fetchPosts() {
  try {
    const now = Date.now();
    if (cachedPosts.length > 0 && now - lastFetched < CACHE_DURATION) {
      return cachedPosts;
    }
    POSTS_CONTAINER.innerHTML = '<p>Loading posts...</p>';
    const response = await fetch(BLOG_URL);
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}. Possible CORS issue or file not found.`);
    }
    const data = await response.text();
    const parser = new DOMParser();
    const xml = parser.parseFromString(data, 'text/xml');
    if (xml.querySelector('parsererror')) {
      throw new Error('Failed to parse XML: Malformed XML structure');
    }
    const posts = Array.from(xml.getElementsByTagName('post')).map((post) => ({
      id: post.getAttribute('id'),
      date: post.getElementsByTagName('date')[0].textContent,
      title: post.getElementsByTagName('title')[0].textContent,
      preview: post.getElementsByTagName('preview')[0].textContent,
      content: post.getElementsByTagName('content')[0].innerHTML,
      timeToRead: post.getElementsByTagName('content')[0].innerHTML.split(' ').length / 200,
      tags: Array.from(post.getElementsByTagName('tag')).map((tag) => tag.textContent),
    }));
    posts.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    cachedPosts = posts;
    lastFetched = now;
    return posts;
  } catch (error) {
    POSTS_CONTAINER.innerHTML = '<p>Failed to load posts. Please try again later.</p>';
    console.error(error);
  }
}
function convertReadTime(timeToRead) {
  return timeToRead >= 1 ? timeToRead.toFixed(0) + ' min read' : (timeToRead * 60).toFixed(0) + 's read';
}
function createPostElement(post) {
  return `
    <div class="post" data-id="${post.id}" onclick="location.hash = '#blog?id=${post.id}'">
      <div class="post-header">
        <em class="post-date">[${post.date}]</em>
        <span class="post-title">${post.title}</span>
        <span class="post-time-to-read">${CONFIG.showEstimatedReadTime ? convertReadTime(post.timeToRead) : ''}</span>
      </div>
      <div class="post-content">
        <span>${post.preview}</span>
        <hr class="dotted">
        <div class="tag-list">
        ${post.tags.map((tag) => `<span class="tag">#${tag}</span>`).join('')}
        </div>
      </div>
    </div>
  `;
}
function initPosts() {
  fetchPosts()
    .then((posts) => (POSTS_CONTAINER.innerHTML = posts.map(createPostElement).join('')))
    .catch((error) => console.error(error));
}
function openPost(postId) {
  fetchPosts()
    .then((posts) => {
      const post = posts.find((p) => p.id === postId);
      if (post) {
        POSTS_CONTAINER.innerHTML = `
                <hr class="dotted">
                <div class="post-header">
                    <em class="post-date">[${post.date}]</em>
                    <span class="post-title">${post.title}</span>
          <span class="post-time-to-read">${CONFIG.showEstimatedReadTime ? convertReadTime(post.timeToRead) : ''}</span>
                </div>
                <div>
                    <p id="post-content-full">${post.content}</p>
                </div>
                <hr class="dotted">
                <div class="post-actions"><a class="post-action-btn" id="post-back-btn">&lt; Back to posts</a><a class="post-action-btn" id="post-share-btn">Share</a></div>
            `;
        const postShareBtn = document.getElementById('post-share-btn');
        postShareBtn.addEventListener('click', () => {
          copyClipboard(window.location.href, postShareBtn, 'Link copied!');
        });
        document.getElementById('post-back-btn').addEventListener('click', () => {
          location.hash = '#blog';
        });
        if (CONFIG.writeAnimationOnPostOpen && !getEffectsDisabledState()) {
          setTimeout(() => {
            writeAnimation(document.getElementById('post-content-full'), 7, 250, true);
          }, 0);
        }
      } else {
        console.error(`Post with ID ${postId} not found`);
        initPosts();
        removeIDFromHash();
      }
    })
    .catch((error) => console.error(error));
}
document.addEventListener('DOMContentLoaded', () => {
  initTheme();
  initEffects();
  if (CONFIG.crtEffect) {
    document.getElementById('canvas').classList.add('crt-effect');
  }
  if (!CONFIG.noiseEffect) {
    document.getElementById('noise-overlay').style.display = 'none';
  }
  if (!CONFIG.grungeOverlay) {
    document.getElementById('grunge-overlay').style.display = 'none';
  }
});
document.addEventListener('DOMContentLoaded', () => {
  if (window.matchMedia('(max-width: 767px)').matches) {
    document.querySelectorAll('details').forEach((details) => {
      details.removeAttribute('open');
    });
  }
  if (CONFIG.crtEffect) {
    document.getElementById('canvas').classList.add('crt-effect');
  }
  if (!CONFIG.noiseEffect) {
    document.getElementById('noise-overlay').style.display = 'none';
  }
  if (!CONFIG.grungeOverlay) {
    document.getElementById('grunge-overlay').style.display = 'none';
  }
  ImgLazyLoading();
  addThemeList();
  initTheme();
  initEffects();
  initEffectsToggle();
  initPosts();
  initPictureColl();
  initRouting();
  initTooltips();
});